  } else if (networkType === 'TON') {
    if (walletType === 'Trust Wallet') {
      return await connectTrustWalletTon();
    } else if (walletType === 'Tonkeeper') {
      return await connectTonkeeper();
    } else {
      throw new Error('Unsupported wallet type for TON network');
